mapper.sql:
WHERE r.user_id = #{userId}

    AND r.type = #{q.type}


    AND r.category_id = #{q.categoryId}


    AND r.category_id IN (SELECT id FROM category WHERE parent_id = #{q.parentCategoryId})


    AND r.record_date >= #{q.startDate}


    AND r.record_date <= #{q.endDate}

mapper.select:
SELECT id, user_id, category_id, type, amount, remark, record_date, create_time
FROM record
WHERE id = #{id} AND user_id = #{userId}

mapper.update:
UPDATE record
SET category_id = #{categoryId}, type = #{type}, amount = #{amount},
    remark = #{remark}, record_date = #{recordDate}
WHERE id = #{id} AND user_id = #{userId}
